const wait = (ms) => new Promise(resolve => setTimeout(resolve, ms));

async function ejecutarSonidos() {
  // 1. Reproducir el primer sonido inmediatamente
  AudioHelper.play({
    src: "modules/cosmere-rpg-tooling/sounds/palabrasaceptadas.mp3",
    volume: 0.8,
    loop: false
  }, true);

  // 2. Esperar 500ms
  await wait(500);

  // 3. Reproducir el segundo sonido
  AudioHelper.play({
    src: "modules/cosmere-rpg-tooling/sounds/thunder.mp3",
    volume: 1.0,
    loop: false
  }, true);
}

ejecutarSonidos();
